label_of_exp_unique.solution:
Lemma label_of_exp_unique : forall P e l,
  P |- e \in l ->
  l = label_of_exp P e.
Proof.
  intros P e l H. induction H; simpl; try reflexivity;
  try (rewrite <- IHexp_has_label1; rewrite <- IHexp_has_label2; reflexivity);
  try (rewrite <- IHexp_has_label1; rewrite <- IHexp_has_label2;
       rewrite <- IHexp_has_label3; reflexivity).
Qed.

cct_typechecker_sound.solution:
Theorem cct_typechecker_sound : forall P PA c,
  cct_typechecker P PA c = true ->
  P ;; PA |-ct- c.
Proof.
  intros P PA c. generalize dependent PA.
  induction c; intros PA H; simpl in *;
    try (repeat rewrite andb_true_iff in *); try econstructor;
    try tauto;
    try (destruct H as [[? ?] ?]; eauto using label_of_exp_sound);
    try (destruct H as [? ?]; eauto using label_of_exp_sound);
    eauto using label_of_exp_sound.
Qed.

cct_typechecker_complete.solution:
Theorem cct_typechecker_complete : forall P PA c,
  cct_typechecker P PA c = false ->
  ~ (P ;; PA |-ct- c).
Proof.
  intros P PA c H Hc. induction Hc; simpl in *;
    try (repeat rewrite andb_false_iff in *); try tauto; try congruence;
    try (apply label_of_exp_unique in H0; rewrite H0 in *; congruence);
    try (apply label_of_exp_unique in H1; rewrite H1 in *;
         destruct H; try congruence; eauto).
Qed.
